            return $container->privates['workflow.registry'];
        }

        $container->privates['workflow.registry'] = $instance;

        $instance->addWorkflow(($container->privates['state_machine.payment'] ?? self::getStateMachine_PaymentService($container)), new \Symfony\Component\Workflow\SupportStrategy\InstanceOfSupportStrategy('App\\Entity\\Payment'));

        return $instance;
    }

    /*
     * Gets the private 'workflow.twig_extension' shared service.
     *
     * @return \Symfony\Bridge\Twig\Extension\WorkflowExtension
     */
    protected static function getWorkflow_TwigExtensionService($container)
    {
        $a = ($container->privates['workflow.registry'] ?? self::getWorkflow_RegistryService($container));

        if (isset($container->privates['workflow.twig_extension'])) {
            return $container->privates['workflow.twig_extension'];
        }

        $instance = new \Symfony\Bridge\Twig\Extension\WorkflowExtension($a);

        if (isset($container->privates['workflow.twig_extension'])) {
            return $container->privates['workflow.twig_extension'];
        }

        return $container->privates['workflow.twig_extension'] = $instance;
    }

    /*
     * Gets the public 'profiler' alias.
     *
     * @return object The ".container.private.profiler" service.
     */
    protected static function getProfilerService($container)
    {
        trigger_deprecation('symfony/framework-bundle', '5.4', 'Accessing the "profiler" service directly from the container is deprecated, use dependency injection instead.');

        return $container->get('.container.private.profiler');
    }

    public function getParameter(string $name): array|bool|string|int|float|\UnitEnum|null
    {
        if (\array_key_exists($name, $this->buildParameters)) {
            return $this->buildParameters[$name];
        }

        if (isset($this->loadedDynamicParameters[$name])) {
            $value = $this->loadedDynamicParameters[$name] ? $this->dynamicParameters[$name] : $this->getDynamicParameter($name);
        } elseif (\array_key_exists($name, $this->parameters) && '.' !== ($name[0] ?? '')) {
            $value = $this->parameters[$name];
        } else {
            throw new ParameterNotFoundException($name, extraMessage: self::NONEMPTY_PARAMETERS[$name] ?? null);
        }

        if (isset(self::NONEMPTY_PARAMETERS[$name]) && (null === $value || '' === $value || [] === $value)) {
            throw new \Symfony\Component\DependencyInjection\Exception\EmptyParameterValueException(self::NONEMPTY_PARAMETERS[$name]);
        }

        return $value;
    }

    public function hasParameter(string $name): bool
    {
        if (\array_key_exists($name, $this->buildParameters)) {
            return true;
        }

        return \array_key_exists($name, $this->parameters) || isset($this->loadedDynamicParameters[$name]);
    }

    public function setParameter(string $name, $value): void
    {
        throw new LogicException('Impossible to call set() on a frozen ParameterBag.');
    }

    public function getParameterBag(): ParameterBagInterface
    {
        if (!isset($this->parameterBag)) {
            $parameters = $this->parameters;
            foreach ($this->loadedDynamicParameters as $name => $loaded) {
                $parameters[$name] = $loaded ? $this->dynamicParameters[$name] : $this->getDynamicParameter($name);
            }
            foreach ($this->buildParameters as $name => $value) {
                $parameters[$name] = $value;
            }
            $this->parameterBag = new FrozenParameterBag($parameters, [], self::NONEMPTY_PARAMETERS);
        }

        return $this->parameterBag;
    }

